defmodule UserScore do
  @type score :: non_neg_integer()
  @type result :: {:ok, score()} | {:error, String.t()}

  @spec calculate(map()) :: result()
  def calculate(%{score: score}) when is_integer(score) and score >= 0 do
    {:ok, score * 2}
  end

  def calculate(%{score: score}) when is_float(score) do
    {:error, "Expected integer, got float: #{score}"}
  end

  def calculate(_), do: {:error, "Missing or invalid score field"}
end

