# Idiomatic: multi-clause over nested case
# Bad
def process(user) do
  case user.active do
    true -> case user.role do
      :admin -> {:ok, :full_access}
      _ -> {:ok, :limited}
    end
    false -> {:error, :inactive}
  end
end

# Good
def process(%{active: false}), do: {:error, :inactive}
def process(%{active: true, role: :admin}), do: {:ok, :full_access}
def process(%{active: true}), do: {:ok, :limited}

defmodule Counter do
  use GenServer

  def start_link(initial \\ 0),
    do: GenServer.start_link(__MODULE__, initial, name: __MODULE__)

  def increment, do: GenServer.cast(__MODULE__, :inc)
  def value,     do: GenServer.call(__MODULE__, :get)

  @impl true
  def init(count), do: {:ok, count}

  @impl true
  def handle_cast(:inc, count), do: {:noreply, count + 1}

  @impl true
  def handle_call(:get, _from, count), do: {:reply, count, count}
end

# Fan-out 10k concurrent API calls — idiomatic Elixir
urls = Enum.map(1..10_000, &"https://api.example.com/user/#{&1}")

{successes, failures} =
  urls
  |> Task.async_stream(&HTTPoison.get/1, max_concurrency: 500, timeout: 5_000)
  |> Enum.reduce({[], []}, fn
    {:ok, {:ok, resp}}, {ok, err} -> {[resp | ok], err}
    {:ok, {:error, reason}}, {ok, err} -> {ok, [reason | err]}
    {:exit, reason}, {ok, err} -> {ok, [reason | err]}
  end)

IO.puts("#{length(successes)} succeeded, #{length(failures)} failed")
